/**
 * @fileoverview TreeView view — DOM construction, rendering, inline editing.
 * @module module/TreeView/view
 */

import razyui from '../../index.js';
import { CLS, SVG, SPELL, ARIA, TEXT, DEFAULTS, PART } from './constants.js';

// ═══════════════════════════════════════
//  DOM Construction
// ═══════════════════════════════════════

/**
 * Build the root TreeView container and attach it to the target element.
 *
 * @param {object} razyui — razyui core reference
 * @param {HTMLElement} el — target element
 * @returns {HTMLElement} container
 */
export function buildContainer(razyui, el) {
    const container = razyui.spell(SPELL.CONTAINER, true)[0];
    razyui(container).addClass('tree-view');
    PART.CONTAINER.apply(container);
    razyui(container).setAttr({ role: ARIA.TREE, tabindex: '0' });
    razyui(el).append(container);
    return container;
}

// ═══════════════════════════════════════
//  Rendering
// ═══════════════════════════════════════

/**
 * Render the full tree into the container.
 *
 * @param {object} razyui
 * @param {HTMLElement} container
 * @param {Array} data — normalized tree nodes
 * @param {object} config
 * @param {string|null} selectedId
 */
export function render(razyui, container, data, config, selectedId) {
    const $container = razyui(container);
    $container.html('');
    const group = razyui.spell(SPELL.GROUP, true)[0];
    const $group = razyui(group);
    $group.setAttr({ role: ARIA.GROUP });

    data.forEach((node, index) => {
        $group.append(createRow(razyui, node, 0, index, config, selectedId));
    });

    $container.append(group);
}

/**
 * Create a single tree row element (recursive for children).
 *
 * @param {object} razyui
 * @param {object} node
 * @param {number} depth
 * @param {number} index
 * @param {object} config
 * @param {string|null} selectedId
 * @returns {HTMLElement}
 */
export function createRow(razyui, node, depth, index, config, selectedId) {
    const hasChildren = node.children && node.children.length > 0;

    // Build row structure via spell()
    const dom = razyui.spell(SPELL.NODE, true);
    const wrapper = dom[0];
    PART.NODE.apply(wrapper);
    wrapper.dataset.id = node.id;

    const row = dom.find('.' + CLS.ROW)[0];
    PART.ROW.apply(row);
    const $row = razyui(row);
    $row.setAttr({ role: ARIA.TREEITEM, 'aria-expanded': hasChildren ? String(node.expanded) : undefined })
        .css('padding-left', (depth * config.indent + DEFAULTS.rowPadBase) + 'px');

    if (selectedId != null && String(selectedId) === String(node.id)) {
        $row.addClass(CLS.SELECTED);
    }

    if (config.draggable) {
        row.draggable = true;
    }

    // Toggle arrow
    const toggle = dom.find('.' + CLS.TOGGLE)[0];
    PART.TOGGLE.apply(toggle);
    if (hasChildren) {
        const $toggle = razyui(toggle);
        $toggle.addClass(CLS.HAS_CHILDREN);
        if (node.expanded) $toggle.addClass(CLS.EXPANDED);
        $toggle.html(SVG.TOGGLE);
    }

    // Checkbox (inserted before label)
    if (config.checkbox) {
        const cb = PART.CHECKBOX.create({ type: 'checkbox', checked: node.checked });
        toggle.after(cb[0]);
    }

    // Icon (inserted before label)
    if (node.icon) {
        const icon = razyui.spell(SPELL.ICON, true)[0];
        PART.ICON.apply(icon);
        razyui(icon).html(node.icon);
        dom.find('.' + CLS.LABEL)[0].before(icon);
    }

    // Label — support onRender callback for custom layout
    const labelEl = dom.find('.' + CLS.LABEL);
    PART.LABEL.apply(labelEl);
    if (typeof config.onRender === 'function') {
        config.onRender(node, labelEl);
    } else {
        labelEl.text(node.label);
    }

    // Action buttons
    const btns = dom.find('.' + CLS.ACTION_BTN);
    btns.forEach(b => PART.ACTION_BTN.apply(b));
    const actionsEl = dom.find('.' + CLS.ACTIONS)[0];
    if (actionsEl) PART.ACTIONS.apply(actionsEl);
    const $addBtn = razyui(btns[0]).setAttr({ type: 'button', title: TEXT.ADD_CHILD }).html(SVG.ADD);
    razyui(btns[1]).setAttr({ type: 'button', title: TEXT.DELETE }).html(SVG.DELETE);

    // Hide "Add child" button when the node disallows children
    if (node.allowChildren === false) {
        $addBtn.css('display', 'none');
    }

    // Children container
    if (node.children && node.children.length > 0) {
        const childContainer = razyui.spell(SPELL.CHILDREN, true)[0];
        PART.CHILDREN.apply(childContainer);
        const $childContainer = razyui(childContainer);
        if (!node.expanded) $childContainer.addClass(CLS.COLLAPSED);

        node.children.forEach((child, ci) => {
            $childContainer.append(createRow(razyui, child, depth + 1, ci, config, selectedId));
        });

        razyui(wrapper).append(childContainer);
    }

    return wrapper;
}

/**
 * Collect all visible (non-collapsed) rows in DOM order.
 *
 * @param {HTMLElement} container
 * @returns {HTMLElement[]}
 */
export function getVisibleRows(container) {
    const rows = [];
    const walk = (parentEl) => {
        const nodes = parentEl.querySelectorAll(':scope > .' + CLS.NODE);
        nodes.forEach(nodeEl => {
            const row = nodeEl.querySelector(':scope > .' + CLS.ROW);
            if (row) rows.push(row);

            const children = nodeEl.querySelector(':scope > .' + CLS.CHILDREN);
            if (children && !razyui(children).hasClass(CLS.COLLAPSED)) {
                walk(children);
            }
        });
    };

    // Start from the top-level group
    const topGroup = container.querySelector(':scope > .' + CLS.GROUP);
    if (topGroup) walk(topGroup);
    return rows;
}

// ═══════════════════════════════════════
//  Inline Editing
// ═══════════════════════════════════════

/**
 * Start inline editing with a control component (e.g. ClipBox).
 *
 * @param {object} razyui — razyui core reference
 * @param {object} node — tree node being edited
 * @param {HTMLElement} labelEl — the .tv-label span to replace
 * @param {object} config — component config
 * @param {Function} onRename — callback (node, oldLabel, newLabel, rawValue?) => void
 */
export function startControlEdit(razyui, node, labelEl, config, onRename) {
    const oldLabel = node.label;
    const editControl = node.editControl || config.editControl;

    const input = PART.EDIT_INPUT.create();

    // For ClipBox: parse current label into comma-separated chips
    const separator = (config.editControlConfig?.separator || node.editControlConfig?.separator || ',');
    if (editControl === 'ClipBox' && node.label) {
        // Use setAttribute so ClipBox's #parseInitialValue() can read it
        // (it uses getAttribute('value'), not the .value DOM property)
        input.attr('value', node.label);
    }

    labelEl.replaceWith(input[0]);

    const controlInstance = new razyui[editControl](input[0], {
        ...(config.editControlConfig || {}),
        ...(node.editControlConfig || {}),
        placeholder: node.label || TEXT.ENTER_VALUE,
        onChange: (value) => {
            node.label = Array.isArray(value)
                ? value.map(v => v.label || v.value || v).join(separator + ' ')
                : String(value || oldLabel);

            if (node.label !== oldLabel && typeof onRename === 'function') {
                onRename(node, oldLabel, node.label, value);
            }
        },
    });

    // ClipBox hides the native input and inserts a .clip-box container
    // after it, so we must listen on that container — not the hidden input.
    const clipBoxContainer = input[0].nextElementSibling;
    const clipBoxInput = clipBoxContainer?.querySelector('.' + CLS.CLIP_BOX_INPUT);
    if (clipBoxInput) clipBoxInput.focus();

    let committed = false;
    const commitEdit = () => {
        if (committed) return;
        committed = true;
        const newLabelEl = razyui.el('span', { className: CLS.LABEL, textContent: node.label });
        input[0].replaceWith(newLabelEl[0]);
        // Remove the control container if it's still in the DOM
        if (clipBoxContainer && clipBoxContainer.parentNode) {
            clipBoxContainer.remove();
        }
        controlInstance.destroy?.();
    };

    // Commit when focus leaves the ClipBox container entirely
    if (clipBoxContainer) {
        razyui(clipBoxContainer).on('focusout', () => {
            setTimeout(() => {
                if (!clipBoxContainer.contains(document.activeElement)) {
                    commitEdit();
                }
            }, DEFAULTS.editBlurDelay);
        });

        razyui(clipBoxContainer).on('keydown', (e) => {
            if (e.key === 'Escape') {
                node.label = oldLabel;
                commitEdit();
            }
        });
    } else {
        // Fallback: no control container found — listen on the input itself
        input.on('blur', () => {
            setTimeout(() => commitEdit(), DEFAULTS.editBlurDelay);
        });
        input.on('keydown', (e) => {
            if (e.key === 'Escape') {
                node.label = oldLabel;
                commitEdit();
            }
        });
        input.focus();
    }
}

/**
 * Start inline editing with a plain text input.
 *
 * @param {object} node — tree node being edited
 * @param {HTMLElement} labelEl — the .tv-label span to replace
 * @param {Function} onRename — callback (node, oldLabel, newLabel) => void
 */
export function startPlainEdit(node, labelEl, onRename) {
    const oldLabel = node.label;

    const input = PART.EDIT_INPUT.create({ type: 'text', value: node.label });

    labelEl.replaceWith(input[0]);
    input[0].focus();
    input[0].select();

    let committed = false;
    const commit = () => {
        if (committed) return;
        committed = true;

        const newLabel = input.val().trim() || oldLabel;
        node.label = newLabel;

        const newLabelEl = razyui.el('span', { className: CLS.LABEL, textContent: newLabel });
        input[0].replaceWith(newLabelEl[0]);

        if (newLabel !== oldLabel && typeof onRename === 'function') {
            onRename(node, oldLabel, newLabel);
        }
    };

    input.on('blur', commit)
         .on('keydown', (e) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            input.blur();
        } else if (e.key === 'Escape') {
            input.val(oldLabel);
            input.blur();
        }
    });
}
