/**
 * @fileoverview TreeView state — reactive state creation.
 * @module module/TreeView/state
 */

/**
 * Create the reactive state set for a TreeView instance.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @returns {Array} [stateRef, setState]
 */
export function createReactiveState(stateFn) {
    return stateFn({
        revision: 0, // bump to trigger re-renders
    });
}
