/**
 * @fileoverview TreeView helpers — pure tree-data utility functions.
 * @module module/TreeView/helpers
 */

import { TEXT, ID_PREFIX } from './constants.js';

/**
 * Generate a unique node ID.
 *
 * @param {Function} hashFn — razyui.hash
 * @param {object} counter — mutable { value: number } counter ref
 * @returns {string}
 */
export function nextId(hashFn, counter) {
    return ID_PREFIX + (++counter.value) + '_' + hashFn();
}

/**
 * Normalize an array of raw node objects, ensuring IDs and defaults.
 *
 * @param {Array} nodes — raw nodes
 * @param {Function} hashFn — razyui.hash
 * @param {object} counter — mutable { value: number } counter ref
 * @returns {Array} normalized nodes
 */
export function normalizeData(nodes, hashFn, counter) {
    return nodes.map(n => normalizeNode(n, hashFn, counter));
}

/**
 * Normalize a single raw node object.
 *
 * @param {object} n — raw node
 * @param {Function} hashFn — razyui.hash
 * @param {object} counter — mutable { value: number } counter ref
 * @returns {object} normalized node
 */
export function normalizeNode(n, hashFn, counter) {
    return {
        id:            n.id ?? nextId(hashFn, counter),
        label:         n.label || TEXT.UNTITLED,
        expanded:      n.expanded ?? false,
        checked:       n.checked ?? false,
        icon:          n.icon || null,
        allowChildren: n.allowChildren ?? true,
        data:          n.data ?? null,
        children:      n.children ? normalizeData(n.children, hashFn, counter) : [],
    };
}

/**
 * Find a node by ID in a tree (recursive).
 *
 * @param {string} id
 * @param {Array} nodes
 * @returns {object|null}
 */
export function findNode(id, nodes) {
    for (const n of nodes) {
        if (String(n.id) === String(id)) return n;
        if (n.children.length > 0) {
            const found = findNode(id, n.children);
            if (found) return found;
        }
    }
    return null;
}

/**
 * Find the parent of a node by child ID.
 *
 * @param {string} id
 * @param {Array} nodes
 * @param {object|null} [parent=null]
 * @returns {object|null|undefined} parent node, null if root-level, undefined if not found
 */
export function findParent(id, nodes, parent = null) {
    for (const n of nodes) {
        if (String(n.id) === String(id)) return parent;
        if (n.children.length > 0) {
            const found = findParent(id, n.children, n);
            if (found !== undefined) return found;
        }
    }
    return undefined;
}

/**
 * Get the path (array of node IDs) from root to a target node.
 *
 * @param {string} id
 * @param {Array} nodes
 * @param {Array} [path=[]]
 * @returns {Array|null}
 */
export function getPath(id, nodes, path = []) {
    for (const n of nodes) {
        if (String(n.id) === String(id)) return [...path, n.id];
        if (n.children.length > 0) {
            const found = getPath(id, n.children, [...path, n.id]);
            if (found) return found;
        }
    }
    return null;
}

/**
 * Check whether descendantId is a descendant of ancestorId.
 *
 * @param {string} ancestorId
 * @param {string} descendantId
 * @param {Array} nodes — root data array
 * @returns {boolean}
 */
export function isDescendant(ancestorId, descendantId, nodes) {
    const ancestor = findNode(ancestorId, nodes);
    if (!ancestor) return false;
    return findNode(descendantId, ancestor.children) !== null;
}

/**
 * Return a clean (serializable) copy of the tree data.
 *
 * @param {Array} nodes
 * @returns {Array}
 */
export function getCleanData(nodes) {
    return nodes.map(n => ({
        id:            n.id,
        label:         n.label,
        expanded:      n.expanded,
        checked:       n.checked,
        icon:          n.icon,
        allowChildren: n.allowChildren,
        data:          n.data ?? null,
        children:      n.children.length > 0 ? getCleanData(n.children) : [],
    }));
}

/**
 * Recursively set checked state on a node and all descendants.
 *
 * @param {object} node
 * @param {boolean} checked
 */
export function setCheckRecursive(node, checked) {
    node.checked = checked;
    node.children.forEach(c => setCheckRecursive(c, checked));
}

/**
 * Walk up the parent chain and reconcile checked state.
 *
 * @param {string} childId
 * @param {Array} data — root data array
 */
export function updateParentChecks(childId, data) {
    const path = getPath(childId, data);
    if (!path || path.length < 2) return;

    // Walk upward from parent
    for (let i = path.length - 2; i >= 0; i--) {
        const parent = findNode(path[i], data);
        if (!parent) continue;
        const allChecked = parent.children.every(c => c.checked);
        // const someChecked = parent.children.some(c => c.checked);
        // Indeterminate handled in render
        parent.checked = allChecked;
    }
}

/**
 * Create a new blank node object.
 *
 * @param {Function} hashFn — razyui.hash
 * @param {object} counter — mutable { value: number }
 * @param {object} [overrides={}] — optional field overrides
 * @returns {object}
 */
export function createNewNode(hashFn, counter, overrides = {}) {
    return {
        id:            overrides.id ?? nextId(hashFn, counter),
        label:         overrides.label ?? TEXT.NEW_ITEM,
        expanded:      overrides.expanded ?? false,
        checked:       overrides.checked ?? false,
        icon:          overrides.icon ?? null,
        allowChildren: overrides.allowChildren ?? true,
        data:          overrides.data ?? null,
        children:      overrides.children ?? [],
    };
}
