/**
 * @fileoverview TreeView component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, SVG icons, defaults, text strings
 *   helpers.js   — tree traversal, data normalization
 *   state.js     — reactive state creation
 *   view.js      — DOM construction, rendering, inline editing
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/TreeView
 */

import { default as razyui } from '../../index.js';

import { DEFAULTS, CLS }                                       from './constants.js';
import { normalizeData, findNode, findParent, getPath,
         isDescendant, getCleanData, setCheckRecursive,
         updateParentChecks, createNewNode }                    from './helpers.js';
import { createReactiveState }                                  from './state.js';
import { buildContainer, render, getVisibleRows,
         startControlEdit, startPlainEdit }                     from './view.js';
import { bindEvents, bindDragDrop, bindNodeActions }           from './events.js';

/**
 * TreeView — v2 modular rewrite
 *
 * Multi-level tree structure with drag-and-drop reordering,
 * inline editing, add/delete nodes, expand/collapse, and reactive state.
 *
 * Features:
 *   - Unlimited nesting depth
 *   - Expand / collapse nodes (animated)
 *   - Drag & drop reorder: within same level, across levels
 *   - Drop indicators: before, after, inside (child)
 *   - Add child / sibling nodes
 *   - Delete nodes (with confirmation callback)
 *   - Inline rename (double-click or F2)
 *   - Keyboard navigation (↑↓ ← → Enter Delete F2)
 *   - Optional checkboxes with tri-state (parent auto-checks)
 *   - Optional icons per node
 *   - Reactive state via razyui.state()
 *   - getControl() API
 *   - Control component integration for editing (ClipBox, etc.)
 *
 * Config:
 *   data          — array of { id, label, children?, icon?, expanded?, checked?, allowChildren?, data?, editControl?, editControlConfig? }
 *   checkbox      — enable checkboxes (default false)
 *   editable      — allow inline rename (default true)
 *   draggable     — allow drag & drop (default true)
 *   indent        — indent per level in px (default 20)
 *   editControl   — control component for editing (e.g., 'ClipBox')
 *   editControlConfig — config passed to the edit control component
 *   onRender(node, labelEl) — custom renderer for node labels; receives node data and razyui-wrapped label element
 *
 * Control Component Integration:
 *   Set editControl: 'ClipBox' to use ClipBox for node editing instead of plain text input.
 *   Per-node override: add editControl/editControlConfig to individual nodes.
 *
 *   Example:
 *     editControl: 'ClipBox',
 *     editControlConfig: { max: 3, placeholder: 'Add tags…' }
 *
 * Callbacks:
 *   onSelect(node, path)           — fires when a node is clicked
 *   onDrop(movedNode, targetNode, position)  — fires after drag-drop
 *   onBeforeAdd(parentNode|null)   — async; return false to cancel, or return an object to override the new node fields
 *   onAdd(parentNode, newNode)     — fires after adding a node
 *   onBeforeDelete(node)           — async; return false to cancel deletion
 *   onDelete(node, parentNode)     — fires after deleting
 *   onRename(node, oldLabel, newLabel, rawValue?) — fires after rename; rawValue = control component value
 *   onCheck(node, checked)         — fires on checkbox toggle
 *   onExpand(node, expanded)       — fires on expand/collapse
 *   onReorder(data)                — fires whenever tree data changes
 * 
 * @class TreeView
 */
const TreeView = class {
    /** @type {HTMLElement} */
    #container = null;
    /** @type {Object} */
    #config = {};
    /** @type {Array} */
    #data = [];
    /** @type {Object} */
    #stateRef = null;
    /** @type {Function} */
    #setState = null;
    /** @type {string|number|null} */
    #selectedId = null;
    /** @type {Object} */
    #idCounter = { value: 0 };
    /** @type {AbortController} */
    #eventAC = null;
    /** @type {AbortController} */
    #dragAC = null;
    /** @type {AbortController} */
    #nodeActionsAC = null;
    #destroyed = false;
    /** @type {boolean} Prevents concurrent async add/delete operations */
    #busy = false;

    /**
     * Creates an instance of TreeView.
     * @param {string|HTMLElement} selector - The container element or selector.
     * @param {Object} [config={}] - Configuration options.
     */
    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve JIT spacing tokens
        this.#config.indent = razyui.JIT.TOKEN.spacePx(this.#config.indent);

        const el = razyui(selector)[0];
        if (!el) { console.warn('TreeView: element not found \u2192', selector); return; }

        // Ensure all nodes have IDs
        this.#data = normalizeData(config.data || [], razyui.hash, this.#idCounter);

        this.#container = buildContainer(razyui, el);

        // ── Reactive state ──
        const [stateRef, setState] = createReactiveState(razyui.state);
        this.#stateRef = stateRef;
        this.#setState = setState;

        this.#renderTree();
        this.#wireEvents();
    }

    // ────────────────────────────────────────────
    // Rendering
    // ────────────────────────────────────────────

    /**
     * Renders the tree view.
     * @private
     */
    #renderTree() {
        render(razyui, this.#container, this.#data, this.#config, this.#selectedId);
    }

    /**
     * Re-renders the tree view and notifies of reorder.
     * @private
     */
    #rerender() {
        this.#renderTree();
        this.#notifyReorder();
    }

    /**
     * Notifies listeners of a reorder event.
     * @private
     */
    #notifyReorder() {
        if (typeof this.#config.onReorder === 'function') {
            this.#config.onReorder(getCleanData(this.#data));
        }
    }

    // ────────────────────────────────────────────
    // Events
    // ────────────────────────────────────────────

    /**
     * Rebinds core events (click, double-click, keydown).
     * @private
     */
    #rebindCoreEvents() {
        const self = this;
        this.#eventAC?.abort();
        this.#eventAC = bindEvents(this.#container, this.#config, {
            onRowClick:      (id) => self.#select(id),
            onToggleClick:   (id) => self.#toggleExpand(id),
            onLabelDblClick: (id, label) => self.#startEdit(id, label),
            onKeydown:       (e) => self.#handleKeydown(e),
        });
    }

    /**
     * Rebinds drag and drop events.
     * @private
     */
    #rebindDragDrop() {
        const self = this;
        this.#dragAC?.abort();
        this.#dragAC = null;
        if (this.#config.draggable) {
            this.#dragAC = bindDragDrop(this.#container, {
                isDescendant: (aId, dId) => isDescendant(aId, dId, self.#data),
                moveNode:     (sId, tId, pos) => self.#moveNode(sId, tId, pos),
                getNode:      (id) => findNode(id, self.#data),
            });
        }
    }

    /**
     * Wires all events.
     * @private
     */
    #wireEvents() {
        const self = this;
        this.#rebindCoreEvents();
        this.#rebindDragDrop();

        this.#nodeActionsAC = bindNodeActions(this.#container, {
            onToggleCheck: (id, checked) => self.#toggleCheck(id, checked),
            onAddChild:    (id) => self.#addChild(id),
            onDeleteNode:  (id) => self.#deleteNode(id),
        });
    }

    // ────────────────────────────────────────────
    // Selection
    // ────────────────────────────────────────────

    /**
     * Selects a node by ID.
     * @param {string|number} id - The ID of the node to select.
     * @private
     */
    #select(id) {
        // Deselect previous
        razyui(this.#container).find('.' + CLS.ROW + '.' + CLS.SELECTED).removeClass(CLS.SELECTED);

        this.#selectedId = id;

        const nodeEl = this.#container.querySelector(`.${CLS.NODE}[data-id="${id}"]`);
        if (nodeEl) {
            const row = nodeEl.querySelector(':scope > .' + CLS.ROW);
            if (row) razyui(row).addClass(CLS.SELECTED);
        }

        const node = findNode(id, this.#data);
        if (node && typeof this.#config.onSelect === 'function') {
            this.#config.onSelect(node, getPath(id, this.#data));
        }
    }

    // ────────────────────────────────────────────
    // Expand / collapse
    // ────────────────────────────────────────────

    /**
     * Toggles the expanded state of a node.
     * @param {string|number} id - The ID of the node to toggle.
     * @private
     */
    #toggleExpand(id) {
        const node = findNode(id, this.#data);
        if (!node || node.children.length === 0) return;

        node.expanded = !node.expanded;

        // Update DOM directly for performance
        const nodeEl = this.#container.querySelector(`.${CLS.NODE}[data-id="${id}"]`);
        if (nodeEl) {
            const toggle   = nodeEl.querySelector(':scope > .' + CLS.ROW + ' .' + CLS.TOGGLE);
            const children = nodeEl.querySelector(':scope > .' + CLS.CHILDREN);

            if (toggle)   razyui(toggle).toggleClass(CLS.EXPANDED, node.expanded);
            if (children) razyui(children).toggleClass(CLS.COLLAPSED, !node.expanded);

            const row = nodeEl.querySelector(':scope > .' + CLS.ROW);
            if (row) razyui(row).setAttr({ 'aria-expanded': String(node.expanded) });
        }

        if (typeof this.#config.onExpand === 'function') {
            this.#config.onExpand(node, node.expanded);
        }
    }

    // ────────────────────────────────────────────
    // Checkbox
    // ────────────────────────────────────────────

    /**
     * Toggles the checked state of a node.
     * @param {string|number} id - The ID of the node to toggle.
     * @param {boolean} checked - The new checked state.
     * @private
     */
    #toggleCheck(id, checked) {
        const node = findNode(id, this.#data);
        if (!node) return;

        // Check this node and all descendants
        setCheckRecursive(node, checked);

        // Update parent chain
        updateParentChecks(id, this.#data);

        this.#rerender();

        if (typeof this.#config.onCheck === 'function') {
            this.#config.onCheck(node, checked);
        }
    }

    // ────────────────────────────────────────────
    // Add / delete
    // ────────────────────────────────────────────

    /**
     * Adds a child node to the specified parent.
     * Supports async onBeforeAdd callback for AJAX confirmation.
     *
     * @param {string|number} parentId - The ID of the parent node.
     * @private
     */
    async #addChild(parentId) {
        if (this.#busy) return;

        const parent = findNode(parentId, this.#data);
        if (!parent) return;

        // Guard: node does not allow children
        if (parent.allowChildren === false) return;

        // AJAX gate — onBeforeAdd can return false to cancel, or an object to override new node fields
        let overrides = {};
        if (typeof this.#config.onBeforeAdd === 'function') {
            this.#busy = true;
            try {
                const result = await this.#config.onBeforeAdd(parent);
                if (result === false) return;
                if (result && typeof result === 'object') overrides = result;
            } finally {
                this.#busy = false;
            }
        }

        const newNode = createNewNode(razyui.hash, this.#idCounter, overrides);

        parent.children.push(newNode);
        parent.expanded = true;

        this.#rerender();
        this.#select(newNode.id);

        // Auto start editing (skip when server already provided the label)
        if (this.#config.editable && !overrides.label) {
            requestAnimationFrame(() => {
                const nodeEl = this.#container.querySelector(`.${CLS.NODE}[data-id="${newNode.id}"]`);
                const label = nodeEl?.querySelector('.' + CLS.LABEL);
                if (label) this.#startEdit(newNode.id, label);
            });
        }

        if (typeof this.#config.onAdd === 'function') {
            this.#config.onAdd(parent, newNode);
        }
    }

    /**
     * Adds a new root node.
     * Supports async onBeforeAdd callback for AJAX confirmation.
     *
     * @returns {Promise<Object|null>} The newly created root node, or null if cancelled.
     */
    async addRoot() {
        if (this.#busy) return null;

        // AJAX gate
        let overrides = {};
        if (typeof this.#config.onBeforeAdd === 'function') {
            this.#busy = true;
            try {
                const result = await this.#config.onBeforeAdd(null);
                if (result === false) return null;
                if (result && typeof result === 'object') overrides = result;
            } finally {
                this.#busy = false;
            }
        }

        const newNode = createNewNode(razyui.hash, this.#idCounter, overrides);

        this.#data.push(newNode);
        this.#rerender();
        this.#select(newNode.id);

        if (this.#config.editable && !overrides.label) {
            requestAnimationFrame(() => {
                const nodeEl = this.#container.querySelector(`.${CLS.NODE}[data-id="${newNode.id}"]`);
                const label = nodeEl?.querySelector('.' + CLS.LABEL);
                if (label) this.#startEdit(newNode.id, label);
            });
        }

        return newNode;
    }

    /**
     * Deletes a node by ID.
     * Supports async onBeforeDelete callback for AJAX confirmation.
     *
     * @param {string|number} id - The ID of the node to delete.
     * @private
     */
    async #deleteNode(id) {
        if (this.#busy) return;

        const node = findNode(id, this.#data);
        if (!node) return;

        // AJAX gate — onBeforeDelete can return false to cancel
        if (typeof this.#config.onBeforeDelete === 'function') {
            this.#busy = true;
            try {
                const result = await this.#config.onBeforeDelete(node);
                if (result === false) return;
            } finally {
                this.#busy = false;
            }
        }

        const parentNode = findParent(id, this.#data);

        // Remove from data
        if (parentNode) {
            parentNode.children = parentNode.children.filter(c => String(c.id) !== String(id));
        } else {
            this.#data = this.#data.filter(c => String(c.id) !== String(id));
        }

        if (String(this.#selectedId) === String(id)) {
            this.#selectedId = null;
        }

        this.#rerender();

        if (typeof this.#config.onDelete === 'function') {
            this.#config.onDelete(node, parentNode);
        }
    }

    // ────────────────────────────────────────────
    // Inline editing
    // ────────────────────────────────────────────

    /**
     * Starts inline editing for a node.
     * @param {string|number} id - The ID of the node to edit.
     * @param {HTMLElement} labelEl - The label element to replace with an editor.
     * @private
     */
    #startEdit(id, labelEl) {
        const node = findNode(id, this.#data);
        if (!node) return;

        const editControl = node.editControl || this.#config.editControl;

        if (editControl && razyui[editControl]) {
            startControlEdit(razyui, node, labelEl, this.#config, this.#config.onRename);
        } else {
            startPlainEdit(node, labelEl, this.#config.onRename);
        }
    }

    // ────────────────────────────────────────────
    // Drag & drop
    // ────────────────────────────────────────────

    /**
     * Moves a node to a new position relative to a target node.
     * @param {string|number} sourceId - The ID of the node to move.
     * @param {string|number} targetId - The ID of the target node.
     * @param {string} position - The position relative to the target ('before', 'after', 'inside').
     * @private
     */
    #moveNode(sourceId, targetId, position) {
        // Extract the source node from its current location
        const sourceNode = findNode(sourceId, this.#data);
        if (!sourceNode) return;

        // Remove from old location
        const sourceParent = findParent(sourceId, this.#data);
        if (sourceParent) {
            sourceParent.children = sourceParent.children.filter(c => String(c.id) !== String(sourceId));
        } else {
            this.#data = this.#data.filter(c => String(c.id) !== String(sourceId));
        }

        if (position === 'inside') {
            // Add as child of target
            const target = findNode(targetId, this.#data);
            if (target) {
                target.children.push(sourceNode);
                target.expanded = true;
            }
        } else {
            // Add before/after target in its parent's children array
            const targetParent = findParent(targetId, this.#data);
            const siblings = targetParent ? targetParent.children : this.#data;
            const targetIndex = siblings.findIndex(c => String(c.id) === String(targetId));

            if (targetIndex !== -1) {
                const insertAt = position === 'before' ? targetIndex : targetIndex + 1;
                siblings.splice(insertAt, 0, sourceNode);
            }
        }

        this.#rerender();
        this.#select(sourceId);

        if (typeof this.#config.onDrop === 'function') {
            const targetNode = findNode(targetId, this.#data);
            this.#config.onDrop(sourceNode, targetNode, position);
        }
    }

    // ────────────────────────────────────────────
    // Keyboard
    // ────────────────────────────────────────────

    /**
     * Handles keyboard navigation and actions.
     * @param {KeyboardEvent} e - The keyboard event.
     * @private
     */
    #handleKeydown(e) {
        // Don't interfere with editing
        if (razyui(e.target).hasClass(CLS.EDIT_INPUT)) return;

        const visibleRows = getVisibleRows(this.#container);
        const currentIdx = visibleRows.findIndex(r => razyui(r).hasClass(CLS.SELECTED));

        switch (e.key) {
            case 'ArrowDown': {
                e.preventDefault();
                const next = currentIdx < visibleRows.length - 1 ? currentIdx + 1 : currentIdx;
                const nextNode = razyui(visibleRows[next]).closest('.' + CLS.NODE);
                if (nextNode.length) this.#select(nextNode.attr('data-id'));
                break;
            }
            case 'ArrowUp': {
                e.preventDefault();
                const prev = currentIdx > 0 ? currentIdx - 1 : 0;
                const prevNode = razyui(visibleRows[prev]).closest('.' + CLS.NODE);
                if (prevNode.length) this.#select(prevNode.attr('data-id'));
                break;
            }
            case 'ArrowRight': {
                e.preventDefault();
                if (this.#selectedId) {
                    const node = findNode(this.#selectedId, this.#data);
                    if (node && node.children.length > 0 && !node.expanded) {
                        this.#toggleExpand(this.#selectedId);
                    }
                }
                break;
            }
            case 'ArrowLeft': {
                e.preventDefault();
                if (this.#selectedId) {
                    const node = findNode(this.#selectedId, this.#data);
                    if (node && node.children.length > 0 && node.expanded) {
                        this.#toggleExpand(this.#selectedId);
                    } else {
                        // Go to parent
                        const parentNode = findParent(this.#selectedId, this.#data);
                        if (parentNode) this.#select(parentNode.id);
                    }
                }
                break;
            }
            case 'Enter': {
                e.preventDefault();
                if (this.#selectedId) {
                    const node = findNode(this.#selectedId, this.#data);
                    if (node && node.children.length > 0) {
                        this.#toggleExpand(this.#selectedId);
                    }
                }
                break;
            }
            case 'F2': {
                e.preventDefault();
                if (this.#selectedId && this.#config.editable) {
                    const nodeEl = this.#container.querySelector(`.${CLS.NODE}[data-id="${this.#selectedId}"]`);
                    const label = nodeEl?.querySelector(':scope > .' + CLS.ROW + ' .' + CLS.LABEL);
                    if (label) this.#startEdit(this.#selectedId, label);
                }
                break;
            }
            case 'Delete':
            case 'Backspace': {
                if (this.#selectedId) {
                    e.preventDefault();
                    this.#deleteNode(this.#selectedId);
                }
                break;
            }
        }
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /**
     * Gets the controller object for the TreeView instance.
     * @returns {Object} The controller object.
     */
    getControl() {
        const self = this;
        return {
            /** Property accessor for 'data' attribute */
            get data()      { return getCleanData(self.#data); },
            set data(v)     { self.#data = normalizeData(Array.isArray(v) ? v : [], razyui.hash, self.#idCounter); self.#selectedId = null; self.#rerender(); },
            get selected()  { return self.#selectedId; },
            set selected(v) { self.#select(v); },
            get draggable() { return self.#config.draggable; },
            set draggable(v){ self.#config.draggable = !!v; self.#rebindDragDrop(); self.#renderTree(); },

            /** Get current tree data */
            getData: () => getCleanData(self.#data),

            /** Replace all data and re-render */
            setData: (data) => {
                self.#data = normalizeData(data, razyui.hash, self.#idCounter);
                self.#selectedId = null;
                self.#rerender();
            },

            /** Get currently selected node */
            getSelected: () => {
                return self.#selectedId ? findNode(self.#selectedId, self.#data) : null;
            },

            /** Select a node by ID */
            select: (id) => { self.#select(id); },

            /** Add a root-level node */
            addRoot: () => self.addRoot(),

            /** Add a child to a node */
            addChild: (parentId) => { self.#addChild(parentId); },

            /** Delete a node */
            delete: (id) => self.#deleteNode(id),

            /** Find a node by ID */
            getNode: (id) => findNode(id, self.#data) || null,

            /** Expand all nodes */
            expandAll: () => {
                const walk = (nodes) => { nodes.forEach(n => { n.expanded = true; walk(n.children); }); };
                walk(self.#data);
                self.#rerender();
            },

            /** Collapse all nodes */
            collapseAll: () => {
                const walk = (nodes) => { nodes.forEach(n => { n.expanded = false; walk(n.children); }); };
                walk(self.#data);
                self.#rerender();
            },

            /** Get checked node IDs (if checkbox enabled) */
            getChecked: () => {
                const ids = [];
                const walk = (nodes) => { nodes.forEach(n => { if (n.checked) ids.push(n.id); walk(n.children); }); };
                walk(self.#data);
                return ids;
            },

            /** Enable or disable inline editing at runtime */
            setEditable: (enabled) => {
                self.#config.editable = !!enabled;
                self.#rebindCoreEvents();
            },

            /** Enable or disable drag-and-drop reordering at runtime */
            setDraggable: (enabled) => {
                self.#config.draggable = !!enabled;
                self.#rebindDragDrop();
                self.#renderTree();
            },

            /** Get the container element */
            get container() { return self.#container; },
            destroy: () => self.destroy(),
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /**
     * Destroys the TreeView instance, cleaning up DOM and events.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        this.#dragAC?.abort();
        this.#nodeActionsAC?.abort();
        if (this.#container && this.#container.parentNode) {
            this.#container.remove();
        }
    }
};

export default TreeView;
