/**
 * @fileoverview TreeView constants — CSS classes, SVG icons, defaults, text strings.
 * @module module/TreeView/constants
 */

import { BLUR_CLOSE_DELAY_MS } from '../shared/tokens/timing.js';
import { ICON_CLOSE_12 } from '../shared/tokens/icons.js';
import Icons from '../Icons.js';
import { TRUNCATE, ICON_BTN_RESET } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    CONTAINER:      'tv-container',
    GROUP:          'tv-group',
    NODE:           'tv-node',
    ROW:            'tv-row',
    TOGGLE:         'tv-toggle',
    LABEL:          'tv-label',
    ACTIONS:        'tv-actions',
    ACTION_BTN:     'tv-action-btn',
    ACTION_DELETE:  'tv-action-delete',
    checkbox:       'tv-checkbox',
    ICON:           'tv-icon',
    CHILDREN:       'tv-children',
    EDIT_INPUT:     'tv-edit-input',
    DROP_INDICATOR: 'tv-drop-indicator',
    DROP_BEFORE:    'tv-drop-before',
    DROP_AFTER:     'tv-drop-after',
    DROP_INSIDE:    'tv-drop-inside',
    SELECTED:       'is-selected',
    DRAGGING:       'is-dragging',
    COLLAPSED:      'is-collapsed',
    EXPANDED:       'is-expanded',
    HAS_CHILDREN:   'has-children',
    CLIP_BOX_INPUT: 'clip-box-input',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    checkbox:        false,
    editable:        true,
    draggable:       true,
    indent:          20,
    rowPadBase:    8,
    dropZoneRatio: 0.25,
    editBlurDelay: BLUR_CLOSE_DELAY_MS,
});

/** SVG icon markup */
export const SVG = Object.freeze({
    TOGGLE: Icons.svg('chevron-right', { size: 12 }),
    ADD:    Icons.svg('plus', { size: 12 }),
    DELETE: ICON_CLOSE_12,
});

/** razyui.spell() patterns */
export const SPELL = Object.freeze({
    CONTAINER: 'div.tv-container[data-slot=container]',
    GROUP:     'div.tv-group[data-slot=group]',
    NODE:      'div.tv-node[data-slot=node](div.tv-row[data-slot=row](span.tv-toggle[data-slot=toggle],span.tv-label[data-slot=label],div.tv-actions[data-slot=actions](button.tv-action-btn[data-slot=action-edit],button.tv-action-btn.tv-action-delete[data-slot=action-delete])))',
    CHILDREN:  'div.tv-children[data-slot=children]',
    ICON:      'span.tv-icon[data-slot=icon]',
});

/** ARIA roles / attributes */
export const ARIA = Object.freeze({
    TREE:     'tree',
    GROUP:    'group',
    TREEITEM: 'treeitem',
});

/** UI text strings */
export const TEXT = Object.freeze({
    UNTITLED:    'Untitled',
    NEW_ITEM:    'New Item',
    ADD_CHILD:   'Add child',
    DELETE:      'Delete',
    ENTER_VALUE: 'Enter value\u2026',
});

/** Node ID prefix */
export const ID_PREFIX = '__tv_';

/** Semantic part names for JIT styling overrides. */
export const PART = defineParts('TreeView', {
    CONTAINER   : { class: 'tv-container', aliases: ['container', 'root'] },
    NODE        : { class: 'tv-node', aliases: ['node'] },
    ROW         : { class: 'tv-row', aliases: ['row'] },
    TOGGLE      : { class: 'tv-toggle', tag: 'span', aliases: ['toggle'] },
    LABEL       : { class: 'tv-label', tag: 'span', aliases: ['label'] },
    ACTIONS     : { class: 'tv-actions', aliases: ['actions'] },
    ACTION_BTN  : { class: 'tv-action-btn', tag: 'button', aliases: ['action-btn'] },
    CHECKBOX    : { class: 'tv-checkbox', tag: 'input', aliases: ['checkbox'] },
    ICON        : { class: 'tv-icon', tag: 'span', aliases: ['icon'] },
    CHILDREN    : { class: 'tv-children', aliases: ['children'] },
    EDIT_INPUT  : { class: 'tv-edit-input', tag: 'input', aliases: ['edit-input'] },
});

PART.CONTAINER.jit = 'relative [border:1px_solid_var(--tv-border)] rounded-[var(--tv-radius)] bg-[var(--tv-bg)] [font-family:inherit] text-[var(--tv-font-size)] fg-[var(--tv-text)] [outline:none] overflow-auto [padding:var(--tv-row-gap)_0]';
PART.NODE.jit     = '';
PART.ROW.jit      = 'flex items-center gap-[var(--tv-row-gap)] h-[var(--tv-row-height)] [padding-right:var(--tv-row-px)] cursor-pointer rounded-[var(--tv-row-radius)] [margin:0_var(--tv-row-gap)] [transition:background_0.1s] hover:bg-[var(--tv-bg-hover)] {is-selected}:bg-[var(--tv-accent-subtle)] {is-selected}:fg-[var(--tv-accent)] [&:hover_.tv-actions]:[opacity:1] ^{is-drop-target}:[box-shadow:inset_0_0_0_2px_var(--tv-accent)]';
PART.TOGGLE.jit   = 'flex items-center justify-center w-[16px] h-[16px] shrink-0 fg-[var(--tv-text-muted)] [transition:transform_0.15s,color_0.1s] rounded-[var(--tv-row-radius)] {is-expanded}:[transform:rotate(90deg)]';
PART.LABEL.jit    = TRUNCATE + ' [user-select:none]';
PART.ACTIONS.jit  = 'flex items-center gap-[2px] [margin-left:auto] [opacity:0] [transition:opacity_0.1s] shrink-0';
PART.ACTION_BTN.jit = ICON_BTN_RESET + ' w-[20px] h-[20px] rounded-[var(--tv-row-radius)] fg-[var(--tv-text-muted)] [transition:background_0.1s,color_0.1s]';
PART.CHECKBOX.jit = 'shrink-0 [accent-color:var(--tv-accent)] cursor-pointer [margin:0]';
PART.ICON.jit     = 'flex items-center justify-center w-[16px] h-[16px] shrink-0 text-[14px] [line-height:1]';
PART.CHILDREN.jit = '{is-collapsed}:hidden';
PART.EDIT_INPUT.jit = 'flex-1 min-w-0 [border:1px_solid_var(--tv-accent)] rounded-[var(--tv-row-radius)] [outline:none] bg-[var(--tv-bg)] [font:inherit] fg-[var(--tv-text)] [padding:1px_4px] h-[22px] [box-shadow:0_0_0_2px_var(--tv-accent-subtle)]';